import React, { useState, useEffect } from 'react';
import { Link, useLocation } from 'react-router-dom';

const navbarStyle = {
  position: 'fixed',
  top: '20px',
  left: '50%',
  transform: 'translateX(-50%)',
  width: '92%',
  maxWidth: '1200px',
  background: 'rgba(255,255,255,0.88)',
  backdropFilter: 'blur(24px) saturate(200%)',
  WebkitBackdropFilter: 'blur(24px) saturate(200%)',
  borderRadius: '28px',
  border: '1px solid rgba(255,255,255,0.5)',
  boxShadow: '0 8px 32px rgba(255,75,122,0.1)',
  padding: '0.5rem 1.8rem',
  zIndex: 1000,
  transition: 'all 0.5s cubic-bezier(0.34,1.56,0.64,1)',
};

const navbarScrolledStyle = {
  ...navbarStyle,
  background: 'rgba(255,255,255,0.94)',
  boxShadow: '0 4px 30px rgba(255,75,122,0.1)',
  top: '10px',
  padding: '0.4rem 1.5rem',
};

const brandIconStyle = {
  background: 'linear-gradient(135deg,#ff6b9d 0%,#ff4d7a 40%,#ff2d5a 80%,#ff6b9d 100%)',
  width: '36px',
  height: '36px',
  borderRadius: '10px',
  display: 'inline-flex',
  alignItems: 'center',
  justifyContent: 'center',
  color: 'white',
  fontSize: '1rem',
  backgroundSize: '200% 200%',
  boxShadow: '0 4px 12px rgba(255,75,122,0.3)',
  flexShrink: 0,
};

export default function Navbar() {
  const [scrolled, setScrolled] = useState(false);
  const [mobileOpen, setMobileOpen] = useState(false);
  const location = useLocation();

  useEffect(() => {
    const onScroll = () => setScrolled(window.scrollY > 50);
    window.addEventListener('scroll', onScroll);
    return () => window.removeEventListener('scroll', onScroll);
  }, []);

  const isActive = (path) => location.pathname === path;

  const linkStyle = (active) => ({
    color: active ? '#ff4d7a' : '#6b7280',
    fontWeight: 500,
    padding: '0.5rem 1.2rem',
    borderRadius: '12px',
    transition: 'all 0.3s',
    textDecoration: 'none',
    fontSize: '0.9rem',
    background: active ? 'rgba(255,75,122,0.08)' : 'transparent',
  });

  return (
    <>
      <style>{`
        @keyframes gradientMove {
          0%,100%{background-position:0% 50%}
          50%{background-position:100% 50%}
        }
        @keyframes pulseGlow {
          0%,100%{box-shadow:0 4px 12px rgba(255,75,122,0.3)}
          50%{box-shadow:0 4px 24px rgba(255,75,122,0.5);transform:scale(1.05)}
        }
        .brand-icon-anim { animation: pulseGlow 3s ease-in-out infinite; }
        .brand-text-anim {
          background: linear-gradient(135deg,#ff6b9d 0%,#ff4d7a 40%,#ff2d5a 80%,#ff6b9d 100%);
          -webkit-background-clip: text;
          -webkit-text-fill-color: transparent;
          background-clip: text;
          background-size: 200% 200%;
          animation: gradientMove 4s ease-in-out infinite;
        }
        .nav-link-hover:hover {
          color: #ff4d7a !important;
          background: rgba(255,75,122,0.06) !important;
        }
        .nav-mobile-panel {
          display: none;
          position: fixed;
          top: 80px;
          left: 5%;
          right: 5%;
          background: rgba(255,255,255,0.88);
          backdrop-filter: blur(24px);
          border-radius: 28px;
          border: 1px solid rgba(255,255,255,0.5);
          padding: 1.5rem;
          box-shadow: 0 8px 32px rgba(255,75,122,0.1);
          z-index: 999;
          flex-direction: column;
          gap: 0.5rem;
        }
        .nav-mobile-panel.open { display: flex; }
        .nav-mobile-link {
          padding: 0.75rem 1rem;
          border-radius: 12px;
          text-decoration: none;
          color: #6b7280;
          font-weight: 500;
          transition: all 0.3s;
        }
        .nav-mobile-link:hover, .nav-mobile-link.active {
          background: rgba(255,75,122,0.06);
          color: #ff4d7a;
        }
        @media (max-width: 768px) {
          .nav-desktop-links { display: none !important; }
          .nav-toggle-btn { display: block !important; }
        }
      `}</style>

      <nav style={scrolled ? navbarScrolledStyle : navbarStyle}>
        <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center' }}>
          <Link to="/" style={{ textDecoration: 'none', display: 'flex', alignItems: 'center', gap: '0.6rem', fontWeight: 900, fontSize: '1.35rem', color: '#1a1a2e', letterSpacing: '-0.5px' }}>
            <span style={brandIconStyle} className="brand-icon-anim">
              <i className="fas fa-code"></i>
            </span>
            <span className="brand-text-anim">4naa</span>
          </Link>

          <div className="nav-desktop-links" style={{ display: 'flex', alignItems: 'center', gap: '0.3rem' }}>
            <Link to="/" style={linkStyle(isActive('/'))} className="nav-link-hover">Beranda</Link>
            <Link to="/project" style={linkStyle(isActive('/project'))} className="nav-link-hover">Project</Link>
            <a href="/#skills" style={linkStyle(false)} className="nav-link-hover">Skill</a>
          </div>

          <button
            className="nav-toggle-btn"
            style={{ display: 'none', background: 'none', border: 'none', fontSize: '1.5rem', color: '#1a1a2e', padding: '0.25rem 0.5rem', borderRadius: '8px', cursor: 'pointer' }}
            onClick={() => setMobileOpen(!mobileOpen)}
          >
            <i className={`fas fa-${mobileOpen ? 'times' : 'bars'}`}></i>
          </button>
        </div>
      </nav>

      <div className={`nav-mobile-panel ${mobileOpen ? 'open' : ''}`}>
        <Link to="/" className={`nav-mobile-link ${isActive('/') ? 'active' : ''}`} onClick={() => setMobileOpen(false)}>Beranda</Link>
        <Link to="/project" className={`nav-mobile-link ${isActive('/project') ? 'active' : ''}`} onClick={() => setMobileOpen(false)}>Project</Link>
        <a href="/#skills" className="nav-mobile-link" onClick={() => setMobileOpen(false)}>Skill</a>
      </div>
    </>
  );
}
